// --- ESTADO ---
let trainingMode = false;
let executionMode = false;
let capturedSteps = [];
let currentBankName = "Desconhecido";
let sampleItem = null; 
let successObserver = null;

const SUCCESS_KEYWORDS = ["sucesso", "salvo", "concluido", "finalizado", "realizado", "gravado", "success", "saved"];

// --- EXECUTOR REAL ---
async function executeItemInPage(payload) {
  const { macro, data } = payload;
  executionMode = true;
  console.log("%c[IdentificaPix IA] Executando...", "color: #3b82f6; font-weight: bold;");

  // Ativa o observador de sucesso para pular automático se o banco der feedback visual
  startSuccessObserver();

  for (const step of macro.steps) {
    if (!executionMode) break; // Interrompe se o observador detectar sucesso antes do fim dos passos

    const element = document.querySelector(step.selector);

    if (!element) {
      console.warn(`[IA] Elemento não encontrado: ${step.selector}`);
      continue;
    }

    await new Promise(r => setTimeout(r, 600));

    if (step.type === "click") {
      element.click();
    } 
    else if (step.type === "input") {
      let valueToInject = step.value;
      if (step.mappedProperty === "name") valueToInject = data.name;
      else if (step.mappedProperty === "amount") valueToInject = data.amount;
      else if (step.mappedProperty === "date") valueToInject = data.date;
      else if (step.mappedProperty === "church") valueToInject = data.church;

      element.value = valueToInject;
      element.dispatchEvent(new Event('input', { bubbles: true }));
      element.dispatchEvent(new Event('change', { bubbles: true }));
      element.dispatchEvent(new Event('blur', { bubbles: true }));
    }
  }

  // Se chegou ao fim dos passos e não detectou sucesso visual, 
  // avisa o app que "terminou sua parte"
  setTimeout(() => {
    if (executionMode) {
        notifyDone(data.id);
    }
  }, 1000);
}

function notifyDone(id) {
    executionMode = false;
    stopSuccessObserver();
    window.postMessage({
        source: "IdentificaPixExt",
        type: "ITEM_DONE",
        payload: { id }
    }, "*");
}

// --- OBSERVADOR DE SUCESSO ---
function startSuccessObserver() {
    if (successObserver) successObserver.disconnect();

    successObserver = new MutationObserver((mutations) => {
        for (const mutation of mutations) {
            if (mutation.addedNodes.length) {
                const text = document.body.innerText.toLowerCase();
                if (SUCCESS_KEYWORDS.some(k => text.includes(k))) {
                    console.log("%c[IdentificaPix IA] Feedback de SUCESSO detectado na página!", "color: #10b981; font-weight: bold;");
                    notifyDone("auto-detect");
                    break;
                }
            }
        }
    });

    successObserver.observe(document.body, { childList: true, subtree: true });
}

function stopSuccessObserver() {
    if (successObserver) {
        successObserver.disconnect();
        successObserver = null;
    }
}

// Bridge: WebApp -> Extension
window.addEventListener("message", async (event) => {
  if (!event.data || event.data.source !== "IdentificaPixIA") return;

  const { type, payload } = event.data;

  if (type === "START_TRAINING") {
    trainingMode = true;
    capturedSteps = [];
    currentBankName = payload.bankName || "Desconhecido";
    sampleItem = payload.sampleItem || null;
  }

  if (type === "STOP_TRAINING") {
    trainingMode = false;
    const targetUrl = window.location.href;
    window.postMessage({
        source: "IdentificaPixExt",
        type: "SAVE_TRAINING",
        payload: { bankName: currentBankName, steps: capturedSteps, targetUrl }
    }, "*");
  }

  if (type === "EXECUTE_ITEM") {
    await executeItemInPage(payload);
  }
});

function generateSelector(el) {
  if (!el) return "unknown";
  if (el.id) return "#" + el.id;
  if (el.name) return `[name="${el.name}"]`;

  let selector = el.tagName.toLowerCase();
  if (el.className && typeof el.className === "string") {
    const classes = el.className.trim().split(/\s+/).filter(c => !c.includes(':')).join('.');
    if (classes) selector += "." + classes;
  }
  return selector;
}

document.addEventListener("click", (e) => {
  if (!trainingMode) return;
  const selector = generateSelector(e.target);
  capturedSteps.push({ type: "click", selector, timestamp: new Date().toISOString() });
}, true);

document.addEventListener("input", (e) => {
  if (!trainingMode) return;
  const el = e.target;
  const selector = generateSelector(el);
  const value = el.value;
  let mappedProperty = null;

  if (sampleItem) {
    if (value === String(sampleItem.name)) mappedProperty = "name";
    else if (value === String(sampleItem.amount)) mappedProperty = "amount";
    else if (value === String(sampleItem.date)) mappedProperty = "date";
    else if (value === String(sampleItem.church)) mappedProperty = "church";
  }

  capturedSteps = capturedSteps.filter(s => s.selector !== selector || s.type !== "input");
  capturedSteps.push({ type: "input", selector, value, mappedProperty, timestamp: new Date().toISOString() });
}, true);

