import React, { createContext, useState, useEffect, useMemo, useCallback } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReconciliation } from '../hooks/useReconciliation';
import { useReportManager } from '../hooks/useReportManager';
import { useReconciliationActions } from '../hooks/useReconciliationActions';
import { useModalController } from '../hooks/useModalController';
import { useDataDeletion } from '../hooks/useDataDeletion';
import { supabase } from '../services/supabaseClient';
import { 
    MatchResult, 
    Transaction,
    ReconciliationStatus,
    MatchMethod
} from '../types';
import { groupResultsByChurch, normalizeString } from '../services/processingService';

export const AppContext = createContext<any>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, systemSettings } = useAuth();
    const { showToast, setIsLoading, setActiveView } = useUI();
    const [initialDataLoaded, setInitialDataLoaded] = useState(false);

    const modalController = useModalController();
    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);

    // --- ESTADO DE AUTOMAÇÃO ---
    const [automationMacros, setAutomationMacros] = useState<any[]>([]);

    const fetchMacros = useCallback(async () => {
        if (!user) return;
        const { data, error } = await supabase
            .from('automation_macros')
            .select('*')
            .eq('user_id', user.id)
            .order('created_at', { ascending: false });

        if (error) {
            console.error("[AppContext] Erro ao buscar macros:", error.message);
            return;
        }
        if (data) {
            console.log("[AppContext] Macros carregadas:", data.length);
            setAutomationMacros(data);
        }
    }, [user]);

    useEffect(() => {
        fetchMacros();
    }, [fetchMacros]);

    const effectiveIgnoreKeywords = useMemo(() => {
        return [...(referenceData.customIgnoreKeywords || []), ...(systemSettings.globalIgnoreKeywords || [])];
    }, [referenceData.customIgnoreKeywords, systemSettings.globalIgnoreKeywords]);

    const reconciliation = useReconciliation({
        user,
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: referenceData.fileModels,
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: effectiveIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast,
        setIsLoading,
        setActiveView
    });

    const reconciliationActions = useReconciliationActions({
        reconciliation,
        referenceData,
        showToast
    });

    const { confirmDeletion } = useDataDeletion({
        user,
        modalController,
        referenceData,
        reportManager,
        reconciliation,
        showToast
    });

    const [isSyncing, setIsSyncing] = useState(false);

    // --- LISTENER DA EXTENSÃO ATUALIZADO (V3) ---
    useEffect(() => {
        const handleExtensionMessage = async (event: MessageEvent) => {
            // Aceita mensagens tanto diretas quanto via chrome.runtime bridge
            if (!event.data || event.data.source !== "IdentificaPixExt") return;

            const { type, payload } = event.data;
            console.log(`[AppContext] Mensagem recebida da Extensão: ${type}`);

            if (type === "SAVE_TRAINING" && user) {
                setIsLoading(true);
                try {
                    const { data, error } = await supabase
                        .from('automation_macros')
                        .insert({
                            user_id: user.id,
                            name: `Macro ${payload.bankName} - ${new Date().toLocaleDateString()}`,
                            steps: payload.steps,
                            target_url: payload.targetUrl || null
                        })
                        .select();

                    if (error) throw error;

                    console.log("[AppContext] Macro salva no DB:", data[0].id);
                    setAutomationMacros(prev => [data[0], ...prev]);
                    showToast("IA: Novo percurso aprendido e habilitado!", "success");
                } catch (e: any) {
                    console.error("[AppContext] Erro ao salvar macro:", e.message);
                    showToast("Erro ao salvar aprendizado.", "error");
                } finally {
                    setIsLoading(false);
                }
            }
        };

        window.addEventListener("message", handleExtensionMessage);
        return () => window.removeEventListener("message", handleExtensionMessage);
    }, [user, setIsLoading, showToast]);

    const saveSmartEdit = useCallback((result: MatchResult) => {
        reconciliation.updateReportData(result);
        if (result.status === 'IDENTIFICADO' && result.contributor && result.church) {
             referenceData.learnAssociation(result);
        }
        modalController.closeSmartEdit();
        showToast("Identificação atualizada.", "success");
    }, [reconciliation, referenceData, modalController, showToast]);

    const openManualIdentify = useCallback((txId: string) => {
        const tx = reconciliation.matchResults.find((r: any) => r.transaction.id === txId)?.transaction;
        if (tx) reconciliation.setManualIdentificationTx(tx);
    }, [reconciliation]);

    const runAiAutoIdentification = useCallback(() => {
        if (reconciliation.matchResults.length === 0) return;

        setIsLoading(true);
        let identifiedCount = 0;

        const currentResults = [...reconciliation.matchResults];
        const nextResults = currentResults.map(res => {
            if (res.status === ReconciliationStatus.UNIDENTIFIED) {
                const txDescNorm = normalizeString(res.transaction.description, effectiveIgnoreKeywords);
                const learned = referenceData.learnedAssociations.find((la: any) => la.normalizedDescription === txDescNorm);

                if (learned) {
                    const church = referenceData.churches.find((c: any) => c.id === learned.churchId);
                    if (church) {
                        identifiedCount++;
                        return {
                            ...res,
                            status: ReconciliationStatus.IDENTIFIED,
                            church: church,
                            matchMethod: MatchMethod.LEARNED,
                            similarity: 100,
                            contributor: res.suggestion || { name: learned.contributorNormalizedName, amount: res.transaction.amount },
                            contributorAmount: res.transaction.amount,
                            suggestion: undefined
                        };
                    }
                }

                if (res.suggestion && (res.similarity || 0) >= 90) {
                    const churchId = (res.suggestion as any)._churchId || res.suggestion.church?.id;
                    const church = referenceData.churches.find((c: any) => c.id === churchId);

                    if (church) {
                        identifiedCount++;
                        return {
                            ...res,
                            status: ReconciliationStatus.IDENTIFIED,
                            contributor: res.suggestion,
                            church: church,
                            matchMethod: MatchMethod.AI,
                            similarity: res.similarity,
                            contributorAmount: res.suggestion.amount,
                            suggestion: undefined
                        };
                    }
                }
            }
            return res;
        });

        if (identifiedCount > 0) {
            reconciliation.setMatchResults(nextResults);
            const incomeResults = nextResults.filter(r => r.transaction.amount >= 0 || r.status === ReconciliationStatus.PENDING);
            const expenseResults = nextResults.filter(r => r.transaction.amount < 0 && r.status !== ReconciliationStatus.PENDING);

            reconciliation.setReportPreviewData({
                income: groupResultsByChurch(incomeResults),
                expenses: { 'all_expenses_group': expenseResults }
            });

            showToast(`${identifiedCount} transações identificadas automaticamente.`, "success");
        } else {
            showToast("Nenhuma sugestão de alta confiança encontrada.", "info");
        }

        setIsLoading(false);
    }, [reconciliation, referenceData, effectiveIgnoreKeywords, setIsLoading, showToast]);

    const handleGmailSyncSuccess = useCallback((transactions: Transaction[]) => {
        reconciliation.importGmailTransactions(transactions);
        setTimeout(() => reconciliation.handleCompare(), 500);
    }, [reconciliation]);

    const summary = useMemo(() => {
        const results = reconciliation.matchResults;
        const hasSession = reconciliation.hasActiveSession;

        let identifiedCount = 0;
        let unidentifiedCount = 0;
        let totalValue = 0;
        let valuePerChurch: [string, number][] = [];
        let methodBreakdown: Record<string, number> = { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0 };

        let autoVal = 0, manualVal = 0, pendingVal = 0;

        if (hasSession && results.length > 0) {
            identifiedCount = results.filter((r: any) => r.status === 'IDENTIFICADO').length;
            unidentifiedCount = results.filter((r: any) => r.status === 'NÃO IDENTIFICADO' || r.status === 'PENDENTE').length;

            results.forEach((r: any) => {
                if (r.status === 'IDENTIFICADO') {
                    const val = r.transaction.amount;
                    totalValue += val;
                    if (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI') manualVal += val;
                    else autoVal += val;

                    const method = r.matchMethod || 'AUTOMATIC';
                    methodBreakdown[method] = (methodBreakdown[method] || 0) + 1;
                } else {
                    pendingVal += (r.contributorAmount || r.transaction.amount);
                }
            });

            const grouped = groupResultsByChurch(results.filter((r: any) => r.status === 'IDENTIFICADO'));
            valuePerChurch = Object.values(grouped).map((group: any) => {
                const churchName = group[0]?.church?.name || 'Desconhecida';
                const total = (group as any[]).reduce((acc: number, curr: any) => acc + curr.transaction.amount, 0);
                return [churchName, total] as [string, number];
            }).sort((a, b) => b[1] - a[1]);

        } else if (reportManager.savedReports.length > 0) {
            reportManager.savedReports.forEach(rep => {
                if (rep.data && rep.data.results) {
                    const repResults = rep.data.results as MatchResult[];
                    identifiedCount += repResults.filter(r => r.status === 'IDENTIFICADO').length;

                    repResults.forEach(r => {
                        if (r.status === 'IDENTIFICADO') {
                            const method = r.matchMethod || 'AUTOMATIC';
                            methodBreakdown[method] = (methodBreakdown[method] || 0) + 1;
                        }
                    });
                }
            });
        }

        return {
            identifiedCount,
            unidentifiedCount,
            totalValue,
            autoConfirmed: { value: autoVal },
            manualConfirmed: { value: manualVal },
            pending: { value: pendingVal },
            valuePerChurch,
            methodBreakdown,
            isHistorical: !hasSession && reportManager.savedReports.length > 0
        };
    }, [reconciliation.matchResults, reconciliation.hasActiveSession, reportManager.savedReports]);

    const activeSpreadsheetData = useMemo(() => {
        if (!reconciliation.activeReportId) return undefined;
        const report = reportManager.savedReports.find(r => r.id === reconciliation.activeReportId);
        return report?.data?.spreadsheet;
    }, [reconciliation.activeReportId, reportManager.savedReports]);

    useEffect(() => {
        if (user !== undefined) setInitialDataLoaded(true);
    }, [user]);

    const value = useMemo(() => ({
        ...referenceData,
        effectiveIgnoreKeywords,
        ...reportManager,
        ...reconciliation,
        ...reconciliationActions,
        ...modalController,
        automationMacros,
        fetchMacros,
        initialDataLoaded,
        summary,
        activeSpreadsheetData,
        saveSmartEdit,
        isSyncing,
        handleGmailSyncSuccess,
        confirmDeletion,
        openManualIdentify,
        runAiAutoIdentification
    }), [
        referenceData, effectiveIgnoreKeywords, reportManager, reconciliation, reconciliationActions,
        modalController, automationMacros, fetchMacros, initialDataLoaded, summary, activeSpreadsheetData, 
        saveSmartEdit, isSyncing, handleGmailSyncSuccess, confirmDeletion, openManualIdentify,
        runAiAutoIdentification
    ]);

    return (
        <AppContext.Provider value={value}>
            {children}
        </AppContext.Provider>
    );
};

// content.js - Injetado em todas as páginas

let localTrainingState = { active: false };
let executionMode = false;
let successObserver = null;
const SUCCESS_KEYWORDS = ["sucesso", "salvo", "concluido", "finalizado", "realizado", "gravado", "success", "saved"];

// Sincroniza estado de treino do storage continuamente
chrome.storage.onChanged.addListener((changes) => {
  if (changes.trainingState) {
    localTrainingState = changes.trainingState.newValue;
    console.log("[IdentificaPix IA] Sincronização de Estado:", localTrainingState.active);
  }
});

// Carga inicial do estado
chrome.storage.local.get(['trainingState'], (result) => {
  if (result.trainingState) localTrainingState = result.trainingState;
});

// --- LISTENER DE MENSAGENS DO BACKGROUND ---
chrome.runtime.onMessage.addListener((msg, sender, sendResponse) => {
  console.log("[IdentificaPix IA] Mensagem recebida do Background:", msg.type);

  if (msg.type === "SAVE_TRAINING") {
    // Tenta postar a mensagem para a janela atual (WebApp)
    window.postMessage({ 
      source: "IdentificaPixExt", 
      type: "SAVE_TRAINING", 
      payload: msg.payload 
    }, "*");
    console.log("[IdentificaPix IA] Encaminhado SAVE_TRAINING para o App via window.postMessage");
  }

  if (msg.type === "EXECUTE_ITEM") {
    executeItemInPage(msg.payload);
  }

  if (msg.type === "ITEM_DONE") {
     window.postMessage({ source: "IdentificaPixExt", type: "ITEM_DONE", payload: msg.payload }, "*");
  }
});

// --- BRIDGE: WEBAPP -> EXTENSION ---
window.addEventListener("message", (event) => {
  // Ignora mensagens de outras origens não identificadas
  if (!event.data || event.data.source !== "IdentificaPixIA") return;

  console.log("[IdentificaPix IA] Comando vindo do App:", event.data.type);
  // Encaminha ordens do App para o Background da Extensão
  chrome.runtime.sendMessage(event.data);
});

// --- CAPTURA DE EVENTOS (MODO TREINO) ---
function generateSelector(el) {
  if (!el) return "unknown";
  if (el.id) return "#" + el.id;
  if (el.name) return `[name="${el.name}"]`;

  let selector = el.tagName.toLowerCase();
  if (el.className && typeof el.className === "string") {
    const classes = el.className.trim().split(/\s+/).filter(c => !c.includes(':')).join('.');
    if (classes) selector += "." + classes;
  }
  return selector;
}

document.addEventListener("click", (e) => {
  if (!localTrainingState.active) return;
  const selector = generateSelector(e.target);
  console.log("[IdentificaPix IA] Capturando Clique:", selector);
  chrome.runtime.sendMessage({
    type: "ACTION_CAPTURED",
    payload: { type: "click", selector, timestamp: new Date().toISOString() }
  });
}, true);

document.addEventListener("input", (e) => {
  if (!localTrainingState.active) return;
  const el = e.target;
  const selector = generateSelector(el);
  const value = el.value;
  let mappedProperty = null;

  const sample = localTrainingState.sampleItem;
  if (sample) {
    if (value === String(sample.name)) mappedProperty = "name";
    else if (value === String(sample.amount)) mappedProperty = "amount";
    else if (value === String(sample.date)) mappedProperty = "date";
    else if (value === String(sample.church)) mappedProperty = "church";
  }

  console.log("[IdentificaPix IA] Capturando Input:", selector, value);
  chrome.runtime.sendMessage({
    type: "ACTION_CAPTURED",
    payload: { type: "input", selector, value, mappedProperty, timestamp: new Date().toISOString() }
  });
}, true);

// --- EXECUTOR (MODO EXECUÇÃO) ---
async function executeItemInPage(payload) {
  const { macro, data } = payload;
  executionMode = true;
  startSuccessObserver();

  console.log("[IdentificaPix IA] Iniciando automação real...");

  for (const step of macro.steps) {
    if (!executionMode) break;
    const element = document.querySelector(step.selector);
    if (!element) {
        console.warn("[IdentificaPix IA] Elemento não encontrado:", step.selector);
        continue;
    }

    await new Promise(r => setTimeout(r, 600));

    if (step.type === "click") {
      element.click();
    } 
    else if (step.type === "input") {
      let valueToInject = step.value;
      if (step.mappedProperty === "name") valueToInject = data.name;
      else if (step.mappedProperty === "amount") valueToInject = data.amount;
      else if (step.mappedProperty === "date") valueToInject = data.date;
      else if (step.mappedProperty === "church") valueToInject = data.church;

      element.value = valueToInject;
      element.dispatchEvent(new Event('input', { bubbles: true }));
      element.dispatchEvent(new Event('change', { bubbles: true }));
      element.dispatchEvent(new Event('blur', { bubbles: true }));
    }
  }

  setTimeout(() => {
    if (executionMode) notifyDone(data.id);
  }, 1000);
}

function notifyDone(id) {
    executionMode = false;
    if (successObserver) successObserver.disconnect();
    chrome.runtime.sendMessage({ type: "ITEM_DONE", payload: { id } });
}

function startSuccessObserver() {
    successObserver = new MutationObserver(() => {
        const text = document.body.innerText.toLowerCase();
        if (SUCCESS_KEYWORDS.some(k => text.includes(k))) {
            notifyDone("auto-detect");
        }
    });
    successObserver.observe(document.body, { childList: true, subtree: true });
}

import React, { createContext, useState, useEffect, useMemo, useCallback } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReconciliation } from '../hooks/useReconciliation';
import { useReportManager } from '../hooks/useReportManager';
import { useReconciliationActions } from '../hooks/useReconciliationActions';
import { useModalController } from '../hooks/useModalController';
import { useDataDeletion } from '../hooks/useDataDeletion';
import { supabase } from '../services/supabaseClient';
import { 
    MatchResult, 
    Transaction,
    ReconciliationStatus,
    MatchMethod
} from '../types';
import { groupResultsByChurch, normalizeString } from '../services/processingService';

export const AppContext = createContext<any>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, systemSettings } = useAuth();
    const { showToast, setIsLoading, setActiveView } = useUI();
    const [initialDataLoaded, setInitialDataLoaded] = useState(false);

    const modalController = useModalController();
    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);

    // --- ESTADO DE AUTOMAÇÃO ---
    const [automationMacros, setAutomationMacros] = useState<any[]>([]);

    const fetchMacros = useCallback(async (silent = false) => {
        if (!user) return;
        if (!silent) console.log("[AppContext] Buscando macros no banco para o usuário:", user.id);

        const { data, error } = await supabase
            .from('automation_macros')
            .select('*')
            .eq('user_id', user.id)
            .order('created_at', { ascending: false });

        if (error) {
            console.error("[AppContext] Erro ao buscar macros:", error.message);
            return;
        }
        if (data) {
            console.log("[AppContext] Macros carregadas com sucesso:", data.length);
            setAutomationMacros(data);
        }
    }, [user]);

    useEffect(() => {
        fetchMacros();
    }, [fetchMacros]);

    const effectiveIgnoreKeywords = useMemo(() => {
        return [...(referenceData.customIgnoreKeywords || []), ...(systemSettings.globalIgnoreKeywords || [])];
    }, [referenceData.customIgnoreKeywords, systemSettings.globalIgnoreKeywords]);

    const reconciliation = useReconciliation({
        user,
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: referenceData.fileModels,
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: effectiveIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast,
        setIsLoading,
        setActiveView
    });

    const reconciliationActions = useReconciliationActions({
        reconciliation,
        referenceData,
        showToast
    });

    const { confirmDeletion } = useDataDeletion({
        user,
        modalController,
        referenceData,
        reportManager,
        reconciliation,
        showToast
    });

    const [isSyncing, setIsSyncing] = useState(false);

    // --- LISTENER DA EXTENSÃO ATUALIZADO (V4) ---
    useEffect(() => {
        const handleExtensionMessage = async (event: MessageEvent) => {
            // Aceita mensagens tanto diretas quanto via chrome.runtime bridge
            if (!event.data || event.data.source !== "IdentificaPixExt") return;

            const { type, payload } = event.data;
            console.log(`%c[AppContext] MENSAGEM RECEBIDA DA EXTENSÃO: ${type}`, "color: #8b5cf6; font-weight: bold;");

            if (type === "SAVE_TRAINING" && user) {
                console.log("[AppContext] Iniciando salvamento da macro no Supabase...");
                setIsLoading(true);
                try {
                    const { data, error } = await supabase
                        .from('automation_macros')
                        .insert({
                            user_id: user.id,
                            name: `Macro ${payload.bankName || 'Treino'} - ${new Date().toLocaleTimeString()}`,
                            steps: payload.steps,
                            target_url: payload.targetUrl || null
                        })
                        .select();

                    if (error) throw error;

                    console.log("[AppContext] Macro salva no DB com ID:", data[0].id);
                    // Atualização imediata do estado
                    setAutomationMacros(prev => [data[0], ...prev]);
                    showToast("IA: Novo percurso aprendido e habilitado!", "success");
                } catch (e: any) {
                    console.error("[AppContext] ERRO CRÍTICO AO SALVAR MACRO NO BANCO:", e.message);
                    showToast("Erro ao salvar aprendizado no banco de dados.", "error");
                } finally {
                    setIsLoading(false);
                }
            }
        };

        window.addEventListener("message", handleExtensionMessage);
        return () => window.removeEventListener("message", handleExtensionMessage);
    }, [user, setIsLoading, showToast]);

    const saveSmartEdit = useCallback((result: MatchResult) => {
        reconciliation.updateReportData(result);
        if (result.status === 'IDENTIFICADO' && result.contributor && result.church) {
             referenceData.learnAssociation(result);
        }
        modalController.closeSmartEdit();
        showToast("Identificação atualizada.", "success");
    }, [reconciliation, referenceData, modalController, showToast]);

    const openManualIdentify = useCallback((txId: string) => {
        const tx = reconciliation.matchResults.find((r: any) => r.transaction.id === txId)?.transaction;
        if (tx) reconciliation.setManualIdentificationTx(tx);
    }, [reconciliation]);

    const runAiAutoIdentification = useCallback(() => {
        if (reconciliation.matchResults.length === 0) return;

        setIsLoading(true);
        let identifiedCount = 0;

        const currentResults = [...reconciliation.matchResults];
        const nextResults = currentResults.map(res => {
            if (res.status === ReconciliationStatus.UNIDENTIFIED) {
                const txDescNorm = normalizeString(res.transaction.description, effectiveIgnoreKeywords);
                const learned = referenceData.learnedAssociations.find((la: any) => la.normalizedDescription === txDescNorm);

                if (learned) {
                    const church = referenceData.churches.find((c: any) => c.id === learned.churchId);
                    if (church) {
                        identifiedCount++;
                        return {
                            ...res,
                            status: ReconciliationStatus.IDENTIFIED,
                            church: church,
                            matchMethod: MatchMethod.LEARNED,
                            similarity: 100,
                            contributor: res.suggestion || { name: learned.contributorNormalizedName, amount: res.transaction.amount },
                            contributorAmount: res.transaction.amount,
                            suggestion: undefined
                        };
                    }
                }

                if (res.suggestion && (res.similarity || 0) >= 90) {
                    const churchId = (res.suggestion as any)._churchId || res.suggestion.church?.id;
                    const church = referenceData.churches.find((c: any) => c.id === churchId);

                    if (church) {
                        identifiedCount++;
                        return {
                            ...res,
                            status: ReconciliationStatus.IDENTIFIED,
                            contributor: res.suggestion,
                            church: church,
                            matchMethod: MatchMethod.AI,
                            similarity: res.similarity,
                            contributorAmount: res.suggestion.amount,
                            suggestion: undefined
                        };
                    }
                }
            }
            return res;
        });

        if (identifiedCount > 0) {
            reconciliation.setMatchResults(nextResults);
            const incomeResults = nextResults.filter(r => r.transaction.amount >= 0 || r.status === ReconciliationStatus.PENDING);
            const expenseResults = nextResults.filter(r => r.transaction.amount < 0 && r.status !== ReconciliationStatus.PENDING);

            reconciliation.setReportPreviewData({
                income: groupResultsByChurch(incomeResults),
                expenses: { 'all_expenses_group': expenseResults }
            });

            showToast(`${identifiedCount} transações identificadas automaticamente.`, "success");
        } else {
            showToast("Nenhuma sugestão de alta confiança encontrada.", "info");
        }

        setIsLoading(false);
    }, [reconciliation, referenceData, effectiveIgnoreKeywords, setIsLoading, showToast]);

    const handleGmailSyncSuccess = useCallback((transactions: Transaction[]) => {
        reconciliation.importGmailTransactions(transactions);
        setTimeout(() => reconciliation.handleCompare(), 500);
    }, [reconciliation]);

    const summary = useMemo(() => {
        const results = reconciliation.matchResults;
        const hasSession = reconciliation.hasActiveSession;

        let identifiedCount = 0;
        let unidentifiedCount = 0;
        let totalValue = 0;
        let valuePerChurch: [string, number][] = [];
        let methodBreakdown: Record<string, number> = { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0 };

        let autoVal = 0, manualVal = 0, pendingVal = 0;

        if (hasSession && results.length > 0) {
            identifiedCount = results.filter((r: any) => r.status === 'IDENTIFICADO').length;
            unidentifiedCount = results.filter((r: any) => r.status === 'NÃO IDENTIFICADO' || r.status === 'PENDENTE').length;

            results.forEach((r: any) => {
                if (r.status === 'IDENTIFICADO') {
                    const val = r.transaction.amount;
                    totalValue += val;
                    if (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI') manualVal += val;
                    else autoVal += val;

                    const method = r.matchMethod || 'AUTOMATIC';
                    methodBreakdown[method] = (methodBreakdown[method] || 0) + 1;
                } else {
                    pendingVal += (r.contributorAmount || r.transaction.amount);
                }
            });

            const grouped = groupResultsByChurch(results.filter((r: any) => r.status === 'IDENTIFICADO'));
            valuePerChurch = Object.values(grouped).map((group: any) => {
                const churchName = group[0]?.church?.name || 'Desconhecida';
                const total = (group as any[]).reduce((acc: number, curr: any) => acc + curr.transaction.amount, 0);
                return [churchName, total] as [string, number];
            }).sort((a, b) => b[1] - a[1]);

        } else if (reportManager.savedReports.length > 0) {
            reportManager.savedReports.forEach(rep => {
                if (rep.data && rep.data.results) {
                    const repResults = rep.data.results as MatchResult[];
                    identifiedCount += repResults.filter(r => r.status === 'IDENTIFICADO').length;

                    repResults.forEach(r => {
                        if (r.status === 'IDENTIFICADO') {
                            const method = r.matchMethod || 'AUTOMATIC';
                            methodBreakdown[method] = (methodBreakdown[method] || 0) + 1;
                        }
                    });
                }
            });
        }

        return {
            identifiedCount,
            unidentifiedCount,
            totalValue,
            autoConfirmed: { value: autoVal },
            manualConfirmed: { value: manualVal },
            pending: { value: pendingVal },
            valuePerChurch,
            methodBreakdown,
            isHistorical: !hasSession && reportManager.savedReports.length > 0
        };
    }, [reconciliation.matchResults, reconciliation.hasActiveSession, reportManager.savedReports]);

    const activeSpreadsheetData = useMemo(() => {
        if (!reconciliation.activeReportId) return undefined;
        const report = reportManager.savedReports.find(r => r.id === reconciliation.activeReportId);
        return report?.data?.spreadsheet;
    }, [reconciliation.activeReportId, reportManager.savedReports]);

    useEffect(() => {
        if (user !== undefined) setInitialDataLoaded(true);
    }, [user]);

    const value = useMemo(() => ({
        ...referenceData,
        effectiveIgnoreKeywords,
        ...reportManager,
        ...reconciliation,
        ...reconciliationActions,
        ...modalController,
        automationMacros,
        fetchMacros,
        initialDataLoaded,
        summary,
        activeSpreadsheetData,
        saveSmartEdit,
        isSyncing,
        handleGmailSyncSuccess,
        confirmDeletion,
        openManualIdentify,
        runAiAutoIdentification
    }), [
        referenceData, effectiveIgnoreKeywords, reportManager, reconciliation, reconciliationActions,
        modalController, automationMacros, fetchMacros, initialDataLoaded, summary, activeSpreadsheetData, 
        saveSmartEdit, isSyncing, handleGmailSyncSuccess, confirmDeletion, openManualIdentify,
        runAiAutoIdentification
    ]);

    return (
        <AppContext.Provider value={value}>
            {children}
        </AppContext.Provider>
    );
};

import React, { useContext, useState, useEffect } from 'react';
import { AppContext } from '../../contexts/AppContext';
import { useTranslation } from '../../contexts/I18nContext';
import { 
    XMarkIcon, 
    BoltIcon, 
    BrainIcon, 
    PlayCircleIcon, 
    ShieldCheckIcon, 
    CheckBadgeIcon, 
    ArrowPathIcon
} from '../Icons';
import { formatCurrency } from '../../utils/formatters';

export const AutoLaunchModal: React.FC = () => {
    const { autoLaunchTarget, closeAutoLaunch, markAsLaunched, automationMacros, fetchMacros } = useContext(AppContext);
    const { t, language } = useTranslation();
    const [step, setStep] = useState<'choice' | 'teaching' | 'executing'>('choice');
    const [currentIndex, setCurrentIndex] = useState(0);
    const [isRefreshing, setIsRefreshing] = useState(false);

    if (!autoLaunchTarget || autoLaunchTarget.length === 0) return null;

    const currentItem = autoLaunchTarget[currentIndex];
    const isFinished = currentIndex >= autoLaunchTarget.length;

    // Pega a macro mais recente do estado global
    const activeMacro = automationMacros && automationMacros.length > 0 ? automationMacros[0] : null;

    const handleRefresh = async () => {
        setIsRefreshing(true);
        await fetchMacros();
        setIsRefreshing(false);
    };

    const startTeaching = () => {
        const sample = {
            id: currentItem.transaction.id,
            name: currentItem.contributor?.name || currentItem.transaction.description,
            amount: currentItem.transaction.amount,
            date: currentItem.transaction.date,
            church: currentItem.church?.name
        };

        console.log("[Modal] Enviando START_TRAINING para a extensão...");
        window.postMessage({ 
            source: "IdentificaPixIA", 
            type: "START_TRAINING", 
            payload: { 
                bankName: "Sistema Alvo",
                sampleItem: sample 
            } 
        }, "*");
        setStep('teaching');
    };

    const stopTrainingAndSave = () => {
        console.log("[Modal] Enviando STOP_TRAINING para a extensão...");
        window.postMessage({ source: "IdentificaPixIA", type: "STOP_TRAINING" }, "*");

        // Volta para a tela de escolha e força um refresh das macros após um breve momento
        setStep('choice');
        setCurrentIndex(0);
        setTimeout(handleRefresh, 2000);
    };

    const startExecution = () => {
        if (!activeMacro) return;
        setStep('executing');
        sendCurrentToExtension();
    };

    const sendCurrentToExtension = () => {
        if (!currentItem || !activeMacro) return;
        window.postMessage({ 
            source: "IdentificaPixIA", 
            type: "EXECUTE_ITEM", 
            payload: { 
                macro: activeMacro,
                data: { 
                    id: currentItem.transaction.id,
                    date: currentItem.transaction.date,
                    name: currentItem.contributor?.name || currentItem.transaction.description,
                    amount: currentItem.transaction.amount,
                    church: currentItem.church?.name
                } 
            } 
        }, "*");
    };

    useEffect(() => {
        const handleExtensionMessage = (event: MessageEvent) => {
            if (event.data?.source !== "IdentificaPixExt") return;

            // Sucesso na execução de um item
            if (event.data?.type === "ITEM_DONE" || event.data?.type === "AUTO_SUCCESS") {
                if (step === 'executing') {
                    confirmCurrentLaunch();
                }
            }
        };
        window.addEventListener("message", handleExtensionMessage);
        return () => window.removeEventListener("message", handleExtensionMessage);
    }, [currentIndex, step, currentItem]);

    const confirmCurrentLaunch = () => {
        const id = currentItem.transaction.id;
        markAsLaunched(id);

        if (currentIndex < autoLaunchTarget.length - 1) {
            setCurrentIndex(prev => prev + 1);
            if (step === 'executing') {
                setTimeout(sendCurrentToExtension, 1500); // Pausa estratégica para o banco respirar
            }
        } else {
            setCurrentIndex(autoLaunchTarget.length);
        }
    };

    return (
        <div className="glass-overlay animate-fade-in">
            <div className="glass-modal w-full max-w-2xl rounded-[2.5rem] animate-scale-in flex flex-col overflow-hidden">
                <div className="px-8 py-6 glass-header flex justify-between items-center shrink-0">
                    <div className="flex items-center gap-3">
                        <div className="p-2.5 bg-amber-500 rounded-2xl text-white shadow-lg shadow-amber-500/30">
                            <BoltIcon className="w-5 h-5" />
                        </div>
                        <div>
                            <h3 className="text-xl font-black text-slate-800 dark:text-white tracking-tight uppercase">Lançamento Automático</h3>
                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-0.5">
                                {isFinished ? 'Processamento Concluído' : `Item ${currentIndex + 1} de ${autoLaunchTarget.length}`}
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-2">
                        {step === 'choice' && (
                            <button 
                                onClick={handleRefresh}
                                className={`p-2 rounded-full transition-all ${isRefreshing ? 'animate-spin text-brand-blue' : 'text-slate-400 hover:text-brand-blue'}`}
                                title="Atualizar Macros"
                            >
                                <ArrowPathIcon className="w-5 h-5" />
                            </button>
                        )}
                        <button onClick={closeAutoLaunch} className="p-2 text-slate-400 hover:text-slate-600 transition-colors">
                            <XMarkIcon className="w-6 h-6" />
                        </button>
                    </div>
                </div>

                <div className="p-8 flex-1 overflow-y-auto custom-scrollbar">
                    {step === 'choice' && (
                        <div className="grid grid-cols-1 gap-4">
                            <button 
                                onClick={startTeaching}
                                className="flex items-center gap-5 p-6 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-3xl hover:border-brand-blue hover:bg-blue-50/50 transition-all text-left group"
                            >
                                <div className="p-4 bg-white dark:bg-slate-800 rounded-2xl shadow-sm group-hover:scale-110 transition-transform">
                                    <BrainIcon className="w-8 h-8 text-purple-600" />
                                </div>
                                <div>
                                    <h4 className="font-black text-slate-800 dark:text-white uppercase text-sm">1. Ensinar novo percurso</h4>
                                    <p className="text-xs text-slate-500 mt-1">Grave as ações no seu sistema financeiro. O sistema aprenderá os campos.</p>
                                </div>
                            </button>

                            <div className="relative group">
                                <button 
                                    onClick={startExecution}
                                    disabled={!activeMacro}
                                    className={`w-full flex items-center gap-5 p-6 border rounded-3xl transition-all text-left ${!activeMacro ? 'opacity-50 grayscale cursor-not-allowed bg-slate-100 dark:bg-slate-900 border-slate-200 dark:border-slate-800' : 'bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-700 hover:border-emerald-500 hover:bg-emerald-50/50'}`}
                                >
                                    <div className="p-4 bg-white dark:bg-slate-800 rounded-2xl shadow-sm group-hover:scale-110 transition-transform">
                                        <PlayCircleIcon className="w-8 h-8 text-emerald-600" />
                                    </div>
                                    <div className="flex-1">
                                        <h4 className="font-black text-slate-800 dark:text-white uppercase text-sm">
                                            {activeMacro ? `2. Executar Lançamento (${activeMacro.name})` : '2. Nenhum percurso ensinado ainda'}
