import React, { useContext, useState, useEffect } from 'react';
import { AppContext } from '../../contexts/AppContext';
import { useTranslation } from '../../contexts/I18nContext';
import { 
    XMarkIcon, 
    BoltIcon, 
    BrainIcon, 
    PlayCircleIcon, 
    ShieldCheckIcon, 
    CheckBadgeIcon, 
    ArrowPathIcon
} from '../Icons';
import { formatCurrency } from '../../utils/formatters';

export const AutoLaunchModal: React.FC = () => {
    const { autoLaunchTarget, closeAutoLaunch, markAsLaunched, automationMacros, fetchMacros } = useContext(AppContext);
    const { t, language } = useTranslation();
    const [step, setStep] = useState<'choice' | 'teaching' | 'executing'>('choice');
    const [currentIndex, setCurrentIndex] = useState(0);
    const [isRefreshing, setIsRefreshing] = useState(false);

    if (!autoLaunchTarget || autoLaunchTarget.length === 0) return null;

    const currentItem = autoLaunchTarget[currentIndex];
    const isFinished = currentIndex >= autoLaunchTarget.length;

    // Pega a macro mais recente do estado global
    const activeMacro = automationMacros && automationMacros.length > 0 ? automationMacros[0] : null;

    const handleRefresh = async () => {
        setIsRefreshing(true);
        await fetchMacros();
        setIsRefreshing(false);
    };

    const startTeaching = () => {
        const sample = {
            id: currentItem.transaction.id,
            name: currentItem.contributor?.name || currentItem.transaction.description,
            amount: currentItem.transaction.amount,
            date: currentItem.transaction.date,
            church: currentItem.church?.name
        };

        console.log("[Modal] Enviando START_TRAINING para a extensão...");
        window.postMessage({ 
            source: "IdentificaPixIA", 
            type: "START_TRAINING", 
            payload: { 
                bankName: "Sistema Alvo",
                sampleItem: sample 
            } 
        }, "*");
        setStep('teaching');
    };

    const stopTrainingAndSave = () => {
        console.log("[Modal] Enviando STOP_TRAINING para a extensão...");
        window.postMessage({ source: "IdentificaPixIA", type: "STOP_TRAINING" }, "*");

        // Volta para a tela de escolha e força um refresh das macros após um breve momento
        setStep('choice');
        setCurrentIndex(0);
        setTimeout(handleRefresh, 2000);
    };

    const startExecution = () => {
        if (!activeMacro) return;
        setStep('executing');
        sendCurrentToExtension();
    };

    const sendCurrentToExtension = () => {
        if (!currentItem || !activeMacro) return;
        window.postMessage({ 
            source: "IdentificaPixIA", 
            type: "EXECUTE_ITEM", 
            payload: { 
                macro: activeMacro,
                data: { 
                    id: currentItem.transaction.id,
                    date: currentItem.transaction.date,
                    name: currentItem.contributor?.name || currentItem.transaction.description,
                    amount: currentItem.transaction.amount,
                    church: currentItem.church?.name
                } 
            } 
        }, "*");
    };

    useEffect(() => {
        const handleExtensionMessage = (event: MessageEvent) => {
            if (event.data?.source !== "IdentificaPixExt") return;

            // Sucesso na execução de um item
            if (event.data?.type === "ITEM_DONE" || event.data?.type === "AUTO_SUCCESS") {
                if (step === 'executing') {
                    confirmCurrentLaunch();
                }
            }
        };
        window.addEventListener("message", handleExtensionMessage);
        return () => window.removeEventListener("message", handleExtensionMessage);
    }, [currentIndex, step, currentItem]);

    const confirmCurrentLaunch = () => {
        const id = currentItem.transaction.id;
        markAsLaunched(id);

        if (currentIndex < autoLaunchTarget.length - 1) {
            setCurrentIndex(prev => prev + 1);
            if (step === 'executing') {
                setTimeout(sendCurrentToExtension, 1500); // Pausa estratégica para o banco respirar
            }
        } else {
            setCurrentIndex(autoLaunchTarget.length);
        }
    };

    return (
        <div className="glass-overlay animate-fade-in">
            <div className="glass-modal w-full max-w-lg rounded-[2rem] animate-scale-in flex flex-col overflow-hidden">
                <div className="px-6 py-4 glass-header flex justify-between items-center shrink-0">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-amber-500 rounded-xl text-white shadow-lg shadow-amber-500/30">
                            <BoltIcon className="w-4 h-4" />
                        </div>
                        <div>
                            <h3 className="text-base font-black text-slate-800 dark:text-white tracking-tight uppercase leading-none">Lançamento Automático</h3>
                            <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mt-1">
                                {isFinished ? 'Concluído' : `Item ${currentIndex + 1} de ${autoLaunchTarget.length}`}
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-1">
                        {step === 'choice' && (
                            <button 
                                onClick={handleRefresh}
                                className={`p-1.5 rounded-full transition-all ${isRefreshing ? 'animate-spin text-brand-blue' : 'text-slate-400 hover:text-brand-blue'}`}
                                title="Atualizar Macros"
                            >
                                <ArrowPathIcon className="w-4 h-4" />
                            </button>
                        )}
                        <button onClick={closeAutoLaunch} className="p-1.5 text-slate-400 hover:text-slate-600 transition-colors">
                            <XMarkIcon className="w-5 h-5" />
                        </button>
                    </div>
                </div>

                <div className="p-6 flex-1 overflow-y-auto custom-scrollbar bg-white dark:bg-slate-900/50">
                    {step === 'choice' && (
                        <div className="grid grid-cols-1 gap-3">
                            <button 
                                onClick={startTeaching}
                                className="flex items-center gap-4 p-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl hover:border-brand-blue hover:bg-blue-50/50 transition-all text-left group"
                            >
                                <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm group-hover:scale-105 transition-transform">
                                    <BrainIcon className="w-6 h-6 text-purple-600" />
                                </div>
                                <div>
                                    <h4 className="font-black text-slate-800 dark:text-white uppercase text-xs">1. Ensinar novo percurso</h4>
                                    <p className="text-[10px] text-slate-500 mt-0.5">Grave as ações no seu sistema financeiro para a IA aprender.</p>
                                </div>
                            </button>

                            <div className="relative group">
                                <button 
                                    onClick={startExecution}
                                    disabled={!activeMacro}
                                    className={`w-full flex items-center gap-4 p-4 border rounded-2xl transition-all text-left ${!activeMacro ? 'opacity-50 grayscale cursor-not-allowed bg-slate-100 dark:bg-slate-900 border-slate-200 dark:border-slate-800' : 'bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-700 hover:border-emerald-500 hover:bg-emerald-50/50'}`}
                                >
                                    <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm group-hover:scale-105 transition-transform">
                                        <PlayCircleIcon className="w-6 h-6 text-emerald-600" />
                                    </div>
                                    <div className="flex-1">
                                        <h4 className="font-black text-slate-800 dark:text-white uppercase text-xs">
                                            {activeMacro ? `2. Executar Lançamento` : '2. Nenhum percurso ensinado'}
                                        </h4>
                                        <p className="text-[10px] text-slate-500 mt-0.5">
                                            {activeMacro ? `Lançar ${autoLaunchTarget.length} registros salvos.` : 'Ensine a IA antes de poder executar.'}
                                        </p>
                                    </div>
                                </button>
                                {!activeMacro && (
                                    <button 
                                        onClick={handleRefresh}
                                        className="absolute right-4 top-1/2 -translate-y-1/2 px-3 py-1.5 bg-brand-blue/10 text-brand-blue rounded-full text-[8px] font-black uppercase tracking-widest hover:bg-brand-blue hover:text-white transition-all border border-brand-blue/20"
                                    >
                                        Atualizar
                                    </button>
                                )}
                            </div>
                        </div>
                    )}

                    {step === 'teaching' && (
                        <div className="text-center py-2 space-y-4">
                            <div className="relative w-14 h-14 mx-auto">
                                <div className="absolute inset-0 bg-purple-500/20 rounded-full animate-ping"></div>
                                <div className="relative bg-purple-600 text-white p-3.5 rounded-full shadow-xl">
                                    <BrainIcon className="w-7 h-7" />
                                </div>
                            </div>
                            <div>
                                <h4 className="text-base font-black text-slate-800 dark:text-white uppercase">Gravando Percurso...</h4>
                                <p className="text-[11px] text-slate-500 mt-1 px-4 leading-relaxed">
                                    Acesse seu sistema e realize o lançamento usando os dados:
                                </p>
                            </div>

                            {!isFinished ? (
                                <div className="bg-slate-50 dark:bg-slate-900 p-4 rounded-2xl border border-slate-200 dark:border-slate-700 text-left animate-fade-in-up">
                                    <div className="grid grid-cols-2 gap-3 mb-4">
                                        <div className="p-2 bg-white dark:bg-slate-800 rounded-lg border border-slate-100">
                                            <p className="text-[7px] font-black text-slate-400 uppercase mb-0.5">Nome</p>
                                            <p className="text-[10px] font-bold text-slate-800 dark:text-white truncate">{currentItem.contributor?.name || currentItem.transaction.description}</p>
                                        </div>
                                        <div className="p-2 bg-white dark:bg-slate-800 rounded-lg border border-slate-100">
                                            <p className="text-[7px] font-black text-slate-400 uppercase mb-0.5">Valor</p>
                                            <p className="text-[10px] font-bold text-emerald-600 font-mono">{currentItem.transaction.amount.toFixed(2)}</p>
                                        </div>
                                    </div>
                                    <div className="flex flex-col gap-2">
                                        <button onClick={stopTrainingAndSave} className="w-full py-2.5 bg-emerald-600 hover:bg-emerald-700 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg shadow-emerald-500/20 transition-all flex items-center justify-center gap-2">
                                            <ShieldCheckIcon className="w-4 h-4" /> Finalizar e Salvar
                                        </button>
                                    </div>
                                </div>
                            ) : (
                                <div className="py-4">
                                    <button onClick={stopTrainingAndSave} className="px-8 py-3 bg-emerald-600 text-white rounded-full font-black uppercase text-[10px] tracking-widest shadow-xl">Salvar Aprendizado</button>
                                </div>
                            )}
                        </div>
                    )}

                    {step === 'executing' && (
                        <div className="space-y-4">
                            {!isFinished ? (
                                <div className="flex flex-col gap-4 animate-fade-in">
                                    <div className="bg-gradient-to-br from-slate-800 to-[#0F172A] p-5 rounded-2xl text-white shadow-xl relative overflow-hidden">
                                        <div className="relative z-10">
                                            <div className="flex items-center gap-1.5 mb-3">
                                                <div className="w-1 h-1 rounded-full bg-emerald-500 animate-pulse"></div>
                                                <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">IA em Operação</span>
                                            </div>

                                            <h4 className="text-lg font-black tracking-tight mb-1 truncate">
                                                {currentItem.contributor?.name || currentItem.transaction.description}
                                            </h4>

                                            <div className="flex flex-wrap gap-2 mt-4">
                                                <div className="px-3 py-1 bg-white/5 rounded-lg border border-white/10">
