                    {step === 'executing' && (
                        <div className="space-y-4">
                            {!isFinished ? (
                                <div className="flex flex-col gap-4 animate-fade-in">
                                    <div className="bg-gradient-to-br from-slate-800 to-[#0F172A] p-5 rounded-2xl text-white shadow-xl relative overflow-hidden">
                                        <div className="relative z-10">
                                            <div className="flex items-center gap-1.5 mb-3">
                                                <div className="w-1 h-1 rounded-full bg-emerald-500 animate-pulse"></div>
                                                <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">IA em Operação Automática</span>
                                            </div>

                                            <h4 className="text-base font-black tracking-tight mb-1 truncate">
                                                {currentItem.contributor?.name || currentItem.transaction.description}
                                            </h4>

                                            <div className="flex flex-wrap gap-2 mt-4">
                                                <div className="px-3 py-1 bg-white/5 rounded-lg border border-white/10">
                                                    <p className="text-[7px] font-bold text-slate-500 uppercase tracking-widest">Valor</p>
                                                    <p className="text-[10px] font-bold text-emerald-400 font-mono">{formatCurrency(currentItem.transaction.amount, language)}</p>
                                                </div>
                                            </div>
                                        </div>
                                    </div>

                                    <div className="flex flex-col items-center gap-2 py-2">
                                        <div className="flex items-center gap-1.5 text-indigo-500 font-black text-[9px] uppercase tracking-widest animate-pulse">
                                            <PlayCircleIcon className="w-3.5 h-3.5" /> IA processando...
                                        </div>
                                        <div className="w-full h-1 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                            <div className="h-full bg-indigo-500 animate-progress"></div>
                                        </div>
                                    </div>
                                </div>
                            ) : (
                                <div className="text-center py-6 animate-scale-in">
                                    <div className="w-16 h-16 bg-emerald-50 dark:bg-emerald-900/20 rounded-full flex items-center justify-center mx-auto mb-4">
                                        <CheckBadgeIcon className="w-8 h-8 text-emerald-500" />
                                    </div>
                                    <h3 className="text-lg font-black text-slate-800 dark:text-white uppercase tracking-tight leading-none">Processamento Concluído</h3>
                                    <button 
                                        onClick={closeAutoLaunch}
                                        className="mt-6 px-10 py-3 bg-brand-blue hover:bg-blue-600 text-white rounded-full font-black uppercase text-[10px] tracking-widest shadow-xl shadow-blue-500/30 transition-all"
                                    >
                                        Fechar
                                    </button>
                                </div>
                            )}

                            <div className="space-y-1.5">
                                <div className="flex justify-between text-[8px] font-black uppercase text-slate-400 tracking-widest">
                                    <span>Progresso do Lote</span>
                                    <span>{Math.round((currentIndex / autoLaunchTarget.length) * 100)}%</span>
                                </div>
                                <div className="w-full bg-slate-100 dark:bg-slate-900 h-1 rounded-full overflow-hidden">
                                    <div 
                                        className="bg-emerald-500 h-full transition-all duration-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]"
                                        style={{ width: `${(currentIndex / autoLaunchTarget.length) * 100}%` }}
                                    ></div>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

import React, { useContext, useMemo } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useTranslation } from '../contexts/I18nContext';
import { UserPlusIcon, XMarkIcon, CheckBadgeIcon, BoltIcon } from './Icons';
import { formatCurrency } from '../utils/formatters';

interface BulkActionToolbarProps {
    selectedIds: string[];
    onClear: () => void;
}

export const BulkActionToolbar: React.FC<BulkActionToolbarProps> = ({ selectedIds, onClear }) => {
    const { matchResults, setBulkIdentificationTxs, setManualIdentificationTx, openAutoLaunch } = useContext(AppContext);
    const { language } = useTranslation();

    const selectedData = useMemo(() => {
        return matchResults.filter((r: any) => selectedIds.includes(r.transaction.id));
    }, [selectedIds, matchResults]);

    const totalAmount = useMemo(() => {
        return selectedData.reduce((acc: number, curr: any) => {
            const val = curr.status === 'PENDENTE' 
                ? (curr.contributorAmount || curr.contributor?.amount || 0)
                : curr.transaction.amount;
            return acc + val;
        }, 0);
    }, [selectedData]);

    if (selectedIds.length === 0) return null;

    const handleBulkIdentify = () => {
        const txsToProcess = selectedData.map((r: any) => r.transaction);
        setBulkIdentificationTxs(txsToProcess);
        setManualIdentificationTx(null);
    };

    return (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[100] animate-fade-in-up">
            <div className="bg-[#051024]/95 text-white px-4 py-2 rounded-full shadow-[0_15px_40px_rgba(0,0,0,0.6)] border border-white/10 flex items-center gap-3 backdrop-blur-xl ring-1 ring-white/10 max-w-lg">

                <div className="flex items-center gap-3 border-r border-white/10 pr-3">
                    <div className="flex flex-col">
                        <span className="text-[7px] font-black text-blue-400 uppercase tracking-widest opacity-80 leading-none">Qtd</span>
                        <span className="text-sm font-black tabular-nums leading-tight">{selectedIds.length}</span>
                    </div>
                    <div className="flex flex-col min-w-[80px]">
                        <span className="text-[7px] font-black text-emerald-400 uppercase tracking-widest opacity-80 leading-none">Soma</span>
                        <span className="text-sm font-black tabular-nums text-emerald-400 leading-tight">
                            {formatCurrency(totalAmount, language)}
                        </span>
                    </div>
                </div>

                <div className="flex items-center gap-1.5">
                    <button
                        onClick={handleBulkIdentify}
                        className="flex items-center gap-1.5 px-3 py-1.5 bg-white/5 hover:bg-white/10 text-white rounded-full text-[8px] font-black uppercase tracking-widest transition-all border border-white/10"
                    >
                        <UserPlusIcon className="w-2.5 h-2.5" />
                        Identificar
                    </button>

                    <button
                        onClick={() => openAutoLaunch(selectedData)}
                        className="flex items-center gap-1.5 px-4 py-1.5 bg-gradient-to-r from-amber-500 to-orange-600 hover:from-amber-400 hover:to-orange-500 text-white rounded-full text-[8px] font-black uppercase tracking-widest shadow-lg shadow-amber-500/20 transition-all hover:-translate-y-1 active:scale-95"
                    >
                        <BoltIcon className="w-2.5 h-2.5 stroke-[3]" />
                        IA
                    </button>

                    <button
                        onClick={onClear}
                        className="p-1.5 hover:bg-white/10 rounded-full text-slate-400 hover:text-white transition-colors ml-1"
                    >
                        <XMarkIcon className="w-3 h-3" />
                    </button>
                </div>
            </div>
        </div>
    );
};

import React, { useContext, useState, useEffect, useRef } from 'react';
import { AppContext } from '../../contexts/AppContext';
import { useTranslation } from '../../contexts/I18nContext';
import { 
    XMarkIcon, 
    BoltIcon, 
    BrainIcon, 
    PlayCircleIcon, 
    ShieldCheckIcon, 
    CheckBadgeIcon, 
    ArrowPathIcon,
    ArrowsRightLeftIcon
} from '../Icons';
import { formatCurrency } from '../../utils/formatters';

export const AutoLaunchModal: React.FC = () => {
    const { autoLaunchTarget, closeAutoLaunch, markAsLaunched, automationMacros, fetchMacros } = useContext(AppContext);
    const { language } = useTranslation();
    const [step, setStep] = useState<'choice' | 'teaching' | 'executing'>('choice');
    const [currentIndex, setCurrentIndex] = useState(0);
    const [isRefreshing, setIsRefreshing] = useState(false);

    // Estados para funcionalidade de arrastar
    const [position, setPosition] = useState<{x: number, y: number} | null>(null);
    const [isDragging, setIsDragging] = useState(false);
    const dragStart = useRef<{x: number, y: number}>({ x: 0, y: 0 });
    const modalRef = useRef<HTMLDivElement>(null);

    if (!autoLaunchTarget || autoLaunchTarget.length === 0) return null;

    const currentItem = autoLaunchTarget[currentIndex];
    const isFinished = currentIndex >= autoLaunchTarget.length;
    const activeMacro = automationMacros && automationMacros.length > 0 ? automationMacros[0] : null;

    const handleRefresh = async () => {
        setIsRefreshing(true);
        await fetchMacros();
        setIsRefreshing(false);
    };

    const handleMouseDown = (e: React.MouseEvent) => {
        if (modalRef.current) {
            setIsDragging(true);
            const rect = modalRef.current.getBoundingClientRect();
            dragStart.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
        }
    };

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (isDragging) {
                const newX = e.clientX - dragStart.current.x;
                const newY = e.clientY - dragStart.current.y;
                setPosition({ x: newX, y: newY });
            }
        };
        const handleMouseUp = () => setIsDragging(false);
        if (isDragging) {
            window.addEventListener('mousemove', handleMouseMove);
            window.addEventListener('mouseup', handleMouseUp);
        }
        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };
    }, [isDragging]);

    const startTeaching = () => {
        const sample = {
            id: currentItem.transaction.id,
            name: currentItem.contributor?.name || currentItem.transaction.description,
            amount: currentItem.transaction.amount,
            date: currentItem.transaction.date,
            church: currentItem.church?.name
        };

        window.postMessage({ 
            source: "IdentificaPixIA", 
            type: "START_TRAINING", 
            payload: { 
                bankName: "Sistema Alvo",
                sampleItem: sample 
            } 
        }, "*");
        setStep('teaching');
    };

    const stopTrainingAndSave = () => {
        window.postMessage({ source: "IdentificaPixIA", type: "STOP_TRAINING" }, "*");
        setStep('choice');
        setCurrentIndex(0);
        setTimeout(handleRefresh, 2000);
    };

    const startExecution = () => {
        if (!activeMacro) return;
        setStep('executing');
        sendCurrentToExtension();
    };

    const sendCurrentToExtension = () => {
        if (!currentItem || !activeMacro) return;
        window.postMessage({ 
            source: "IdentificaPixIA", 
            type: "EXECUTE_ITEM", 
            payload: { 
                macro: activeMacro,
                data: { 
                    id: currentItem.transaction.id,
                    date: currentItem.transaction.date,
                    name: currentItem.contributor?.name || currentItem.transaction.description,
                    amount: currentItem.transaction.amount,
                    church: currentItem.church?.name
                } 
            } 
        }, "*");
    };

    useEffect(() => {
        const handleExtensionMessage = (event: MessageEvent) => {
            if (event.data?.source !== "IdentificaPixExt") return;
            if (event.data?.type === "ITEM_DONE" || event.data?.type === "AUTO_SUCCESS") {
                if (step === 'executing') confirmCurrentLaunch();
            }
        };
        window.addEventListener("message", handleExtensionMessage);
        return () => window.removeEventListener("message", handleExtensionMessage);
    }, [currentIndex, step, currentItem]);

    const confirmCurrentLaunch = () => {
        const id = currentItem.transaction.id;
        markAsLaunched(id);
        if (currentIndex < autoLaunchTarget.length - 1) {
            setCurrentIndex(prev => prev + 1);
            if (step === 'executing') setTimeout(sendCurrentToExtension, 1500);
        } else {
            setCurrentIndex(autoLaunchTarget.length);
        }
    };

    return (
        <div className="fixed inset-0 z-[1000] flex justify-end items-start p-6 pointer-events-none">
            {/* O overlay agora não bloqueia a visão, apenas o clique fora do modal se necessário */}
            <div className="absolute inset-0 pointer-events-none"></div>

            <div 
                ref={modalRef}
                style={{ 
                    position: position ? 'fixed' : 'relative', 
                    left: position ? position.x : 'auto', 
                    top: position ? position.y : 'auto', 
                    margin: 0,
                    transform: position ? 'none' : undefined,
                    pointerEvents: 'auto'
                }}
                className="glass-modal w-full max-w-[340px] rounded-[2rem] animate-scale-in flex flex-col overflow-hidden shadow-[0_20px_60px_rgba(0,0,0,0.4)] border border-white/20"
            >
                <div 
                    onMouseDown={handleMouseDown}
                    className="px-4 py-3 glass-header flex justify-between items-center shrink-0 cursor-move select-none group"
                >
                    <div className="flex items-center gap-2.5">
                        <div className="p-1.5 bg-amber-500 rounded-lg text-white shadow-lg shadow-amber-500/30 group-hover:scale-110 transition-transform">
                            <BoltIcon className="w-4 h-4" />
                        </div>
                        <div>
                            <h3 className="text-xs font-black text-slate-800 dark:text-white tracking-tight uppercase leading-none">Lançamento IA</h3>
                            <p className="text-[7px] font-bold text-slate-400 uppercase tracking-widest mt-1">
                                {isFinished ? 'Concluído' : `${currentIndex + 1} de ${autoLaunchTarget.length}`}
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-1">
                        {step === 'choice' && (
                            <button 
                                onClick={handleRefresh}
                                className={`p-1 rounded-full transition-all ${isRefreshing ? 'animate-spin text-brand-blue' : 'text-slate-400 hover:text-brand-blue'}`}
                                onMouseDown={(e) => e.stopPropagation()}
                            >
                                <ArrowPathIcon className="w-3.5 h-3.5" />
                            </button>
                        )}
                        <button 
                            onClick={closeAutoLaunch} 
                            className="p-1 text-slate-400 hover:text-slate-600 transition-colors"
                            onMouseDown={(e) => e.stopPropagation()}
                        >
                            <XMarkIcon className="w-4 h-4" />
                        </button>
                    </div>
                </div>

                <div className="p-4 flex-1 overflow-y-auto custom-scrollbar bg-white/95 dark:bg-slate-900/95">
                    {step === 'choice' && (
                        <div className="flex flex-col gap-2.5">
                            <button 
                                onClick={startTeaching}
                                className="flex items-center gap-3 p-3.5 bg-slate-50 dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 rounded-2xl hover:border-brand-blue hover:bg-blue-50/50 transition-all text-left group"
                            >
                                <div className="p-2.5 bg-white dark:bg-slate-800 rounded-xl shadow-sm group-hover:scale-105 transition-transform">
                                    <BrainIcon className="w-5 h-5 text-purple-600" />
                                </div>
                                <div>
                                    <h4 className="font-black text-slate-800 dark:text-white uppercase text-[10px]">1. Novo Percurso</h4>
                                    <p className="text-[8px] text-slate-500 leading-tight">Grave as ações manuais.</p>
                                </div>
                            </button>

                            <div className="relative group">
                                <button 
                                    onClick={startExecution}
                                    disabled={!activeMacro}
                                    className={`w-full flex items-center gap-3 p-3.5 border rounded-2xl transition-all text-left ${!activeMacro ? 'opacity-50 grayscale cursor-not-allowed bg-slate-100 dark:bg-slate-900/30 border-slate-200 dark:border-slate-800' : 'bg-slate-50 dark:bg-slate-800/50 border-slate-200 dark:border-slate-700 hover:border-emerald-500 hover:bg-emerald-50/50'}`}
                                >
                                    <div className="p-2.5 bg-white dark:bg-slate-800 rounded-xl shadow-sm group-hover:scale-105 transition-transform">
                                        <PlayCircleIcon className="w-5 h-5 text-emerald-600" />
                                    </div>
                                    <div className="flex-1">
                                        <h4 className="font-black text-slate-800 dark:text-white uppercase text-[10px]">
                                            {activeMacro ? `2. Iniciar Lote` : '2. Sem Percurso'}
                                        </h4>
                                        <p className="text-[8px] text-slate-500 leading-tight">
                                            {activeMacro ? `Lançar todos via IA.` : 'Ensine primeiro.'}
                                        </p>
                                    </div>
                                </button>
                                {!activeMacro && (
                                    <button 
                                        onClick={handleRefresh}
                                        className="absolute right-3 top-1/2 -translate-y-1/2 px-2 py-1 bg-brand-blue/10 text-brand-blue rounded-lg text-[7px] font-black uppercase tracking-widest hover:bg-brand-blue hover:text-white transition-all"
                                    >
                                        Atu.
                                    </button>
                                )}
                            </div>
                        </div>
                    )}

                    {step === 'teaching' && (
                        <div className="text-center py-1 space-y-3">
                            <div className="relative w-10 h-10 mx-auto">
                                <div className="absolute inset-0 bg-purple-500/20 rounded-full animate-ping"></div>
                                <div className="relative bg-purple-600 text-white p-2 rounded-full shadow-xl">
                                    <BrainIcon className="w-6 h-6" />
                                </div>
                            </div>
                            <h4 className="text-xs font-black text-slate-800 dark:text-white uppercase tracking-tight leading-none">Gravando...</h4>

                            {!isFinished ? (
                                <div className="bg-slate-50 dark:bg-slate-800/50 p-3 rounded-2xl border border-slate-200 dark:border-slate-700 text-left animate-fade-in-up">
                                    <div className="space-y-2 mb-3">
                                        <div className="p-2 bg-white dark:bg-slate-800 rounded-lg border border-slate-100">
                                            <p className="text-[6px] font-black text-slate-400 uppercase">Nome</p>
                                            <p className="text-[10px] font-bold text-slate-800 dark:text-white truncate">{currentItem.contributor?.name || currentItem.transaction.description}</p>
                                        </div>
                                        <div className="p-2 bg-white dark:bg-slate-800 rounded-lg border border-slate-100">
                                            <p className="text-[6px] font-black text-slate-400 uppercase">Valor</p>
                                            <p className="text-[10px] font-bold text-emerald-600 font-mono">{currentItem.transaction.amount.toFixed(2)}</p>
                                        </div>
                                    </div>
                                    <button onClick={stopTrainingAndSave} className="w-full py-2 bg-emerald-600 hover:bg-emerald-700 text-white rounded-xl text-[8px] font-black uppercase tracking-widest shadow-lg shadow-emerald-500/20 transition-all flex items-center justify-center gap-2">
                                        <ShieldCheckIcon className="w-3.5 h-3.5" /> Salvar Aprendizado
                                    </button>
                                </div>
                            ) : null}
                        </div>
                    )}

                    {step === 'executing' && (
                        <div className="space-y-3">
                            {!isFinished ? (
                                <div className="flex flex-col gap-3 animate-fade-in">
                                    <div className="bg-gradient-to-br from-slate-800 to-[#0F172A] p-4 rounded-2xl text-white shadow-xl relative overflow-hidden">
                                        <div className="relative z-10">
                                            <div className="flex items-center gap-1 mb-2">
                                                <div className="w-1 h-1 rounded-full bg-emerald-500 animate-pulse"></div>
                                                <span className="text-[7px] font-black text-slate-400 uppercase tracking-widest">Processando...</span>
                                            </div>
                                            <h4 className="text-xs font-black tracking-tight mb-1 truncate">
                                                {currentItem.contributor?.name || currentItem.transaction.description}
                                            </h4>
                                            <p className="text-[11px] font-bold text-emerald-400 font-mono">{formatCurrency(currentItem.transaction.amount, language)}</p>
                                        </div>
                                    </div>

                                    <div className="flex flex-col items-center gap-1.5 py-1">
                                        <div className="flex items-center gap-1.5 text-indigo-500 font-black text-[8px] uppercase tracking-widest animate-pulse">
                                            <PlayCircleIcon className="w-3 h-3" /> IA em Operação
                                        </div>
                                        <div className="w-full h-1 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                            <div className="h-full bg-indigo-500 animate-progress"></div>
                                        </div>
                                    </div>
                                </div>
                            ) : (
                                <div className="text-center py-4 animate-scale-in">
                                    <div className="w-12 h-12 bg-emerald-50 dark:bg-emerald-900/20 rounded-full flex items-center justify-center mx-auto mb-3">
                                        <CheckBadgeIcon className="w-6 h-6 text-emerald-500" />
                                    </div>
                                    <h3 className="text-sm font-black text-slate-800 dark:text-white uppercase tracking-tight leading-none">Concluído!</h3>
                                    <button 
                                        onClick={closeAutoLaunch}
