                                    onClick={startExecution}
                                    disabled={!activeMacro}
                                    className={`w-full flex items-center gap-3 p-3 border rounded-xl transition-all text-left ${!activeMacro ? 'opacity-40 grayscale cursor-not-allowed bg-slate-50 border-slate-100' : 'bg-white dark:bg-slate-800 border-slate-100 dark:border-slate-800 hover:border-emerald-500 hover:shadow-sm'}`}
                                >
                                    <div className={`p-2 rounded-lg transition-colors ${!activeMacro ? 'bg-slate-200 text-slate-400' : 'bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600'}`}>
                                        <PlayCircleIcon className="w-5 h-5" />
                                    </div>
                                    <div className="flex-1">
                                        <h4 className="font-black text-slate-800 dark:text-white uppercase text-[10px]">
                                            {activeMacro ? `2. Iniciar Lançamento` : '2. Sem Percurso'}
                                        </h4>
                                        <p className="text-[8px] text-slate-500 leading-tight">
                                            {activeMacro ? `Lançar todos os itens via IA.` : 'Ensine a IA antes de poder executar.'}
                                        </p>
                                    </div>
                                </button>
                                {!activeMacro && (
                                    <button 
                                        onClick={handleRefresh}
                                        className="absolute right-3 top-1/2 -translate-y-1/2 px-2 py-1 bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-slate-300 rounded-lg text-[7px] font-black uppercase tracking-widest hover:bg-brand-blue hover:text-white transition-all border border-slate-200 dark:border-slate-600"
                                    >
                                        Atu.
                                    </button>
                                )}
                            </div>
                        </div>
                    )}

                    {step === 'teaching' && (
                        <div className="text-center py-2 space-y-4">
                            <div className="relative w-12 h-12 mx-auto">
                                <div className="absolute inset-0 bg-purple-500/20 rounded-full animate-ping"></div>
                                <div className="relative bg-purple-600 text-white p-3 rounded-full shadow-xl">
                                    <BrainIcon className="w-6 h-6" />
                                </div>
                            </div>
                            <h4 className="text-xs font-black text-slate-800 dark:text-white uppercase tracking-tight">Gravando Percurso...</h4>

                            {!isFinished && (
                                <button onClick={stopTrainingAndSave} className="w-full py-2.5 bg-emerald-600 hover:bg-emerald-700 text-white rounded-lg text-[9px] font-black uppercase tracking-widest shadow-lg shadow-emerald-500/20 transition-all flex items-center justify-center gap-2">
                                    <ShieldCheckIcon className="w-3.5 h-3.5" /> Salvar Aprendizado
                                </button>
                            )}
                        </div>
                    )}

                    {step === 'executing' && (
                        <div className="space-y-4">
                            {!isFinished ? (
                                <div className="flex flex-col gap-3 animate-fade-in">
                                    <div className="bg-slate-900 p-4 rounded-xl text-white shadow-xl relative overflow-hidden">
                                        <div className="absolute top-0 right-0 w-24 h-24 bg-brand-blue/10 rounded-full blur-3xl"></div>
                                        <div className="relative z-10">
                                            <div className="flex items-center gap-1.5 mb-2">
                                                <div className="w-1 h-1 rounded-full bg-emerald-500 animate-pulse"></div>
                                                <span className="text-[7px] font-black text-slate-400 uppercase tracking-widest">IA em Operação</span>
                                            </div>
                                            <h4 className="text-[11px] font-black tracking-tight mb-1 truncate uppercase">
                                                {currentItem.contributor?.name || currentItem.transaction.description}
                                            </h4>
                                            <p className="text-lg font-black text-emerald-400 font-mono tracking-tighter leading-none">
                                                {formatCurrency(currentItem.transaction.amount, language)}
                                            </p>
                                        </div>
                                    </div>

                                    <div className="flex flex-col items-center gap-2 py-1">
                                        <div className="flex items-center gap-1.5 text-brand-blue font-black text-[9px] uppercase tracking-widest animate-pulse">
                                            <PlayCircleIcon className="w-3.5 h-3.5" /> IA processando...
                                        </div>
                                        <div className="w-full h-1 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                            <div className="h-full bg-brand-blue animate-progress"></div>
                                        </div>
                                    </div>
                                </div>
                            ) : (
                                <div className="text-center py-4 animate-scale-in">
                                    <div className="w-14 h-14 bg-emerald-50 dark:bg-emerald-900/20 rounded-full flex items-center justify-center mx-auto mb-4 border border-emerald-100 dark:border-emerald-800">
                                        <CheckBadgeIcon className="w-7 h-7 text-emerald-500" />
                                    </div>
                                    <h3 className="text-sm font-black text-slate-800 dark:text-white uppercase tracking-tight">Lote Concluído</h3>
                                    <button 
                                        onClick={closeAutoLaunch}
                                        className="mt-6 w-full py-3 bg-brand-blue hover:bg-blue-600 text-white rounded-xl font-black uppercase text-[9px] tracking-widest shadow-xl shadow-blue-500/20 transition-all active:scale-95"
                                    >
                                        Fechar Janela
                                    </button>
                                </div>
                            )}

                            <div className="space-y-1.5">
                                <div className="flex justify-between text-[7px] font-black uppercase text-slate-400 tracking-widest">
                                    <span>Progresso do Lote</span>
                                    <span>{Math.round((currentIndex / autoLaunchTarget.length) * 100)}%</span>
                                </div>
                                <div className="w-full bg-slate-100 dark:bg-slate-800 h-1 rounded-full overflow-hidden">
                                    <div 
                                        className="bg-emerald-500 h-full transition-all duration-500"
                                        style={{ width: `${(currentIndex / autoLaunchTarget.length) * 100}%` }}
                                    ></div>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

import React, { useContext, useState } from 'react';
import { AppContext } from '../../contexts/AppContext';
import { useTranslation } from '../../contexts/I18nContext';
import { XMarkIcon, SparklesIcon, DocumentArrowDownIcon, UploadIcon, ArrowsRightLeftIcon, BoltIcon } from '../Icons';
import { ComparisonType } from '../../types';

interface InitialComparisonModalProps {
    onClose: () => void;
}

export const InitialComparisonModal: React.FC<InitialComparisonModalProps> = ({ onClose }) => {
    const { 
        similarityLevel, 
        setSimilarityLevel, 
        dayTolerance, 
        setDayTolerance,
        handleCompare,
        comparisonType,
        setComparisonType
    } = useContext(AppContext);

    const { t } = useTranslation();
    const [isProcessing, setIsProcessing] = useState(false);

    const handleRun = async () => {
        setIsProcessing(true);
        // Pequeno delay para feedback visual do botão carregando
        setTimeout(async () => {
            // Chama o processamento passando os valores ATUAIS definidos no formulário
            await handleCompare(comparisonType, similarityLevel, dayTolerance);
            setIsProcessing(false);
            onClose();
        }, 100);
    };

    const TypeOption = ({ value, label, icon: Icon, colorClass }: { value: ComparisonType, label: string, icon: any, colorClass: string }) => {
        const isSelected = comparisonType === value;
        return (
            <button
                type="button"
                onClick={() => setComparisonType(value)}
                className={`
                    relative flex-1 flex items-center justify-center py-2.5 px-4 rounded-xl border-2 transition-all duration-200 gap-2
                    ${isSelected 
                        ? `bg-white dark:bg-slate-800 ${colorClass} shadow-md transform scale-105 z-10` 
                        : 'bg-slate-50 dark:bg-slate-900 border-transparent text-slate-400 hover:bg-white dark:hover:bg-slate-800 hover:border-slate-200 dark:hover:border-slate-700'
                    }
                `}
            >
                <Icon className={`w-4 h-4 ${isSelected ? '' : 'opacity-50'}`} />
                <span className={`text-[10px] font-black uppercase tracking-widest ${isSelected ? '' : 'opacity-70'}`}>{label}</span>
                {isSelected && (
                    <div className="absolute -top-1.5 -right-1.5 w-3.5 h-3.5 rounded-full bg-current border-2 border-white dark:border-slate-800 shadow-sm animate-pulse"></div>
                )}
            </button>
        );
    };

    return (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-white dark:bg-slate-800 rounded-[2rem] shadow-2xl w-full max-w-lg border border-slate-200 dark:border-slate-700 animate-scale-in overflow-hidden flex flex-col max-h-[90vh]">

                {/* Header */}
                <div className="px-8 py-6 border-b border-slate-100 dark:border-slate-700 flex justify-between items-center bg-slate-50/50 dark:bg-slate-900/30">
                    <div className="flex items-center gap-3">
                        <div className="p-2.5 bg-gradient-to-br from-brand-blue to-indigo-600 rounded-xl text-white shadow-lg shadow-blue-500/30">
                            <BoltIcon className="w-5 h-5" />
                        </div>
                        <div>
                            <h3 className="text-xl font-black text-slate-800 dark:text-white tracking-tight">Configurar Conciliação</h3>
                            <p className="text-xs text-slate-500 dark:text-slate-400 font-medium">Defina os parâmetros antes de processar.</p>
                        </div>
                    </div>
                    <button type="button" onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors">
                        <XMarkIcon className="w-5 h-5" />
                    </button>
                </div>

                {/* Body - Scrollable */}
                <div className="p-8 overflow-y-auto custom-scrollbar space-y-8">

                    {/* 1. Comparison Type - Layout Horizontal Compacto */}
                    <div className="space-y-3">
                        <label className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest ml-1">
                            {t('upload.comparisonType')}
                        </label>
                        <div className="flex gap-3">
                            <TypeOption 
                                value="income" 
                                label={t('upload.income')} 
                                icon={DocumentArrowDownIcon} 
                                colorClass="border-emerald-500 text-emerald-600 dark:text-emerald-400"
                            />
                            <TypeOption 
                                value="expenses" 
                                label={t('upload.expenses')} 
                                icon={UploadIcon} 
                                colorClass="border-rose-500 text-rose-600 dark:text-rose-400"
                            />
                            <TypeOption 
                                value="both" 
                                label={t('upload.both')} 
                                icon={ArrowsRightLeftIcon} 
                                colorClass="border-blue-500 text-blue-600 dark:text-blue-400"
                            />
                        </div>
                    </div>

                    {(comparisonType === 'income' || comparisonType === 'both') && (
                        <div className="space-y-8 animate-fade-in">
                            {/* Similarity Slider */}
                            <div className="space-y-3">
                                <div className="flex justify-between items-end">
                                    <label className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">
                                        {t('settings.similarityLevel')}
                                    </label>
                                    <span className="text-sm font-black text-brand-blue dark:text-blue-400 bg-blue-50 dark:bg-blue-900/30 px-2 py-0.5 rounded-lg border border-blue-100 dark:border-blue-800">
                                        {similarityLevel}%
                                    </span>
                                </div>
                                <div className="relative h-2 bg-slate-100 dark:bg-slate-700 rounded-full">
                                    <div className="absolute top-0 left-0 h-full bg-brand-blue rounded-full transition-all duration-150" style={{ width: `${similarityLevel}%` }}></div>
                                    <input 
                                        type="range" 
                                        min="10" 
                                        max="100" 
                                        value={similarityLevel} 
                                        onChange={e => setSimilarityLevel(parseInt(e.target.value, 10))} 
                                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" 
                                    />
                                </div>
                                <p className="text-[10px] text-slate-400 leading-relaxed">
                                    Rigor na comparação de nomes. <strong className="text-slate-600 dark:text-slate-300">Recomendado: 55%</strong>.
                                </p>
                            </div>

                            {/* Tolerance Slider */}
                            <div className="space-y-3">
                                <div className="flex justify-between items-end">
                                    <label className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">
                                        {t('settings.dayTolerance')}
                                    </label>
                                    <span className="text-sm font-black text-brand-teal dark:text-teal-400 bg-teal-50 dark:bg-teal-900/30 px-2 py-0.5 rounded-lg border border-teal-100 dark:border-teal-800">
                                        {dayTolerance} dias
                                    </span>
                                </div>
                                <div className="relative h-2 bg-slate-100 dark:bg-slate-700 rounded-full">
                                    <div className="absolute top-0 left-0 h-full bg-brand-teal rounded-full transition-all duration-150" style={{ width: `${(dayTolerance / 30) * 100}%` }}></div>
                                    <input 
                                        type="range" 
                                        min="0" 
                                        max="30" 
                                        value={dayTolerance} 
                                        onChange={e => setDayTolerance(parseInt(e.target.value, 10))} 
                                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" 
                                    />
                                </div>
                                <p className="text-[10px] text-slate-400 leading-relaxed">
                                    Flexibilidade para datas (fins de semana/feriados). <strong className="text-slate-600 dark:text-slate-300">Recomendado: 2 dias</strong>.
                                </p>
                            </div>
                        </div>
                    )}
                </div>

                {/* Footer - Botão com Gradiente Âmbar/Laranja */}
                <div className="bg-slate-50 dark:bg-slate-900/30 px-8 py-6 flex justify-end space-x-3 border-t border-slate-100 dark:border-slate-700/50">
                    <button type="button" onClick={onClose} className="px-6 py-3 text-xs font-bold rounded-full border border-slate-300 dark:border-slate-600 text-slate-600 dark:text-slate-300 hover:bg-white dark:hover:bg-slate-800 hover:shadow-sm transition-all uppercase tracking-wide">
                        {t('common.cancel')}
                    </button>
                    <button 
                        type="button" 
                        onClick={handleRun} 
                        disabled={isProcessing}
                        className="flex items-center gap-2 px-8 py-3 text-xs font-bold text-white bg-gradient-to-r from-amber-500 to-orange-600 hover:from-amber-600 hover:to-orange-700 rounded-full shadow-lg shadow-amber-500/30 hover:-translate-y-0.5 transition-all uppercase tracking-wide disabled:opacity-70 disabled:cursor-not-allowed border border-white/10"
                    >
                        {isProcessing ? (
                            <>
                                <svg className="animate-spin h-3 w-3 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                Processando...
                            </>
                        ) : (
                            <>
                                <SparklesIcon className="w-3.5 h-3.5" />
                                Iniciar Processamento
                            </>
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
};
